class Solution:
    def minimumCost(self, source: str, target: str, original: List[str], changed: List[str], cost: List[int]) -> int:
        import sys
        import heapq

        # Step 1: Build the graph with minimum cost between characters
        INF = float('inf')
        dist = [[INF] * 26 for _ in range(26)]
        for i in range(26):
            dist[i][i] = 0

        for o, c, co in zip(original, changed, cost):
            o_idx = ord(o) - ord('a')
            c_idx = ord(c) - ord('a')
            dist[o_idx][c_idx] = min(dist[o_idx][c_idx], co)

        # Step 2: Floyd-Warshall to compute all-pairs shortest paths
        for k in range(26):
            for i in range(26):
                for j in range(26):
                    if dist[i][k] + dist[k][j] < dist[i][j]:
                        dist[i][j] = dist[i][k] + dist[k][j]

        # Step 3: Calculate the total cost to convert source to target
        total_cost = 0
        for s_char, t_char in zip(source, target):
            s_idx = ord(s_char) - ord('a')
            t_idx = ord(t_char) - ord('a')
            if dist[s_idx][t_idx] == INF:
                return -1
            total_cost += dist[s_idx][t_idx]

        return total_cost
